    94→    
    95→    /// Get bridge scaffold behavior interface from object
    96→    pub fn get_bridge_scaffold_behavior_interface_from_object(
    97→        obj: Arc<RwLock<Object>>
    98→    ) -> Option<Arc<Mutex<dyn BridgeScaffoldBehaviorInterface>>> {
    99→        let obj_read = obj.read().unwrap();
   100→        let behaviors = obj_read.get_behavior_modules();
   101→        
   102→        for behavior in behaviors {
   103→            let behavior_lock = behavior.lock().unwrap();
   104→            if let Some(scaffold_interface) = behavior_lock.get_bridge_scaffold_behavior_interface() {
   105→                return Some(scaffold_interface);
   106→            }
   107→        }
   108→        
   109→        None
   110→    }
   111→    
   112→    /// Perform vertical motion (rise/sink)
   113→    fn do_vertical_motion(&mut self) -> Result<Bool, Box<dyn std::error::Error>> {
   114→        let me = self.get_object()?;
   115→        let mut me_write = me.write()?;
   116→        let current_pos = me_write.get_position()?;
   117→        
   118→        // Calculate movement toward target
   119→        let direction = (self.target_pos - current_pos).normalized();
   120→        let distance_to_target = (self.target_pos - current_pos).magnitude();
   121→        
   122→        if distance_to_target < 0.1 {
   123→            // Close enough to target - snap to exact position
   124→            me_write.set_position(&self.target_pos)?;
   125→            return Ok(true); // Motion complete
   126→        }
   127→        
   128→        // Move toward target at vertical speed
   129→        let movement = direction * self.vertical_speed;
   130→        let new_pos = current_pos + movement;
   131→        me_write.set_position(&new_pos)?;
   132→        
   133→        Ok(false) // Motion still in progress
   134→    }
   135→    
   136→    /// Perform lateral motion
   137→    fn do_lateral_motion(&mut self) -> Result<Bool, Box<dyn std::error::Error>> {
   138→        let me = self.get_object()?;
   139→        let mut me_write = me.write()?;
   140→        let current_pos = me_write.get_position()?;
   141→        
   142→        // Calculate movement toward target
   143→        let direction = (self.target_pos - current_pos).normalized();
   144→        let distance_to_target = (self.target_pos - current_pos).magnitude();
   145→        
   146→        if distance_to_target < 0.1 {
   147→            // Close enough to target - snap to exact position
   148→            me_write.set_position(&self.target_pos)?;
   149→            return Ok(true); // Motion complete
   150→        }
   151→        
   152→        // Move toward target at lateral speed
   153→        let movement = direction * self.lateral_speed;
   154→        let new_pos = current_pos + movement;
   155→        me_write.set_position(&new_pos)?;
   156→        
   157→        Ok(false) // Motion still in progress
   158→    }
   159→    
   160→    /// Update target position based on current motion state
   161→    fn update_target_position(&mut self) {
   162→        match self.target_motion {
   163→            ScaffoldTargetMotion::Still => {
   164→                // No movement - target is current position
   165→                if let Ok(me) = self.get_object() {
   166→                    if let Ok(me_read) = me.read() {
   167→                        if let Ok(pos) = me_read.get_position() {
   168→                            self.target_pos = pos.clone();
   169→                        }
   170→                    }
   171→                }
   172→            }
   173→            ScaffoldTargetMotion::Rise => {
   174→                self.target_pos = self.rise_to_pos.clone();
   175→            }
   176→            ScaffoldTargetMotion::BuildAcross => {
   177→                self.target_pos = self.build_pos.clone();
   178→            }
   179→            ScaffoldTargetMotion::TearDownAcross => {
   180→                self.target_pos = self.rise_to_pos.clone();
   181→            }
   182→            ScaffoldTargetMotion::Sink => {
   183→                self.target_pos = self.create_pos.clone();
   184→            }
   185→        }
   186→    }
