   237→// Implement UpdateModuleInterface
   238→impl UpdateModuleInterface for BridgeScaffoldBehavior {
   239→    fn update(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   240→        match self.target_motion {
   241→            ScaffoldTargetMotion::Still => {
   242→                // Not moving - sleep until motion changes
   243→                Ok(crate::modules::UPDATE_SLEEP_FOREVER)
   244→            }
   245→            ScaffoldTargetMotion::Rise | ScaffoldTargetMotion::Sink => {
   246→                // Vertical motion
   247→                let motion_complete = self.do_vertical_motion()?;
   248→                if motion_complete {
   249→                    self.target_motion = ScaffoldTargetMotion::Still;
   250→                    Ok(crate::modules::UPDATE_SLEEP_FOREVER)
   251→                } else {
   252→                    Ok(1) // Continue next frame
   253→                }
   254→            }
   255→            ScaffoldTargetMotion::BuildAcross | ScaffoldTargetMotion::TearDownAcross => {
   256→                // Lateral motion
   257→                let motion_complete = self.do_lateral_motion()?;
   258→                if motion_complete {
   259→                    self.target_motion = ScaffoldTargetMotion::Still;
   260→                    Ok(crate::modules::UPDATE_SLEEP_FOREVER)
   261→                } else {
   262→                    Ok(1) // Continue next frame
   263→                }
   264→            }
   265→        }
   266→    }
   267→}
