   316→// Serialization support
   317→impl BridgeScaffoldBehavior {
   318→    pub fn crc(&self, xfer: &mut dyn Xfer) -> Result<(), Box<dyn std::error::Error>> {
   319→        self.base.crc(xfer)
   320→    }
   321→    
   322→    pub fn xfer(&mut self, xfer: &mut dyn Xfer) -> Result<(), Box<dyn std::error::Error>> {
   323→        let current_version: XferVersion = 1;
   324→        let mut version = current_version;
   325→        xfer.xfer_version(&mut version, current_version)?;
   326→        
   327→        self.base.xfer(xfer)?;
   328→        
   329→        // Transfer motion state
   330→        let mut motion_value = self.target_motion as u8;
   331→        xfer.xfer_byte(&mut motion_value)?;
   332→        if xfer.is_reading() {
   333→            self.target_motion = match motion_value {
   334→                0 => ScaffoldTargetMotion::Still,
   335→                1 => ScaffoldTargetMotion::Rise,
   336→                2 => ScaffoldTargetMotion::BuildAcross,
   337→                3 => ScaffoldTargetMotion::TearDownAcross,
   338→                4 => ScaffoldTargetMotion::Sink,
   339→                _ => ScaffoldTargetMotion::Still,
   340→            };
   341→        }
   342→        
   343→        // Transfer positions
   344→        xfer.xfer_coord3d(&mut self.create_pos)?;
   345→        xfer.xfer_coord3d(&mut self.rise_to_pos)?;
   346→        xfer.xfer_coord3d(&mut self.build_pos)?;
   347→        xfer.xfer_coord3d(&mut self.target_pos)?;
   348→        
   349→        // Transfer speeds
   350→        xfer.xfer_real(&mut self.lateral_speed)?;
   351→        xfer.xfer_real(&mut self.vertical_speed)?;
   352→        
   353→        Ok(())
   354→    }
   355→    
   356→    pub fn load_post_process(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   357→        self.base.load_post_process()
   358→    }
   359→}
